   592→                                    final String... processorNames) {
   593→        Objects.requireNonNull(storeBuilder, "storeBuilder cannot be null");
   594→        addStateStore(StoreBuilderWrapper.wrapStoreBuilder(storeBuilder), false, processorNames);
   595→    }
   596→
