   598→                                    final String... processorNames) {
   599→        addStateStore(storeFactory, false, processorNames);
   600→    }
   601→
   602→    public final void addStateStore(final StoreFactory storeFactory,
   603→                                    final boolean allowOverride,
   604→                                    final String... processorNames) {
   605→        Objects.requireNonNull(storeFactory, "stateStoreFactory cannot be null");
   606→        final String storeName = storeFactory.storeName();
   607→        Objects.requireNonNull(storeName, "state store name cannot be null");
   608→
   609→        final StoreFactory stateFactory = stateFactories.get(storeName);
   610→        if (!allowOverride && stateFactory != null && !stateFactory.isCompatibleWith(storeFactory)) {
   611→            throw new TopologyException("A different StateStore has already been added with the name " + storeName);
   612→        }
   613→        if (globalStateBuilders.containsKey(storeName)) {
   614→            throw new TopologyException("A different GlobalStateStore has already been added with the name " + storeName);
   615→        }
   616→
   617→        stateFactories.put(storeName, storeFactory);
   618→
   619→        if (processorNames != null) {
   620→            for (final String processorName : processorNames) {
   621→                Objects.requireNonNull(processorName, "processor cannot not be null");
   622→                connectProcessorAndStateStore(processorName, storeName);
   623→            }
   624→        }
   625→
   626→        nodeGroups = null;
   627→    }
   628→
   629→    public final <KIn, VIn> void addGlobalStore(final String sourceName,
   630→                                                final TimestampExtractor timestampExtractor,
   631→                                                final Deserializer<KIn> keyDeserializer,
   632→                                                final Deserializer<VIn> valueDeserializer,
   633→                                                final String topic,
   634→                                                final String processorName,
   635→                                                final ProcessorSupplier<KIn, VIn, Void, Void> stateUpdateSupplier,
   636→                                                final boolean reprocessOnRestore) {
   637→        verifyName(sourceName);
   638→
   639→        Objects.requireNonNull(topic, "topic cannot be null");
   640→        validateTopicNotAlreadyRegistered(topic);
   641→
   642→        verifyName(processorName);
   643→        if (sourceName.equals(processorName)) {
   644→            throw new TopologyException("sourceName and processorName must be different.");
   645→        }
   646→
   647→        ApiUtils.checkSupplier(stateUpdateSupplier);
   648→        final Set<StoreBuilder<?>> stores = stateUpdateSupplier.stores();
   649→        if (stores == null || stores.size() != 1) {
   650→            throw new IllegalArgumentException(
   651→                "Global stores must pass in suppliers with exactly one store but got " +
   652→                    (stores != null ? stores.size() : 0));
   653→        }
   654→        final StoreFactory storeFactory =
   655→            StoreBuilderWrapper.wrapStoreBuilder(stores.iterator().next());
   656→
   657→        final String storeName = storeFactory.storeName();
   658→        if (stateFactories.containsKey(storeName)) {
   659→            throw new TopologyException("A different StateStore has already been added with the name " + storeName);
   660→        }
   661→        if (globalStateBuilders.containsKey(storeName)) {
   662→            throw new TopologyException("A different GlobalStateStore has already been added with the name " + storeName);
   663→        }
   664→
   665→        final String[] topics = {topic};
   666→        final String[] predecessors = {sourceName};
   667→
   668→        final ProcessorNodeFactory<KIn, VIn, Void, Void> nodeFactory = new ProcessorNodeFactory<>(
   669→            processorName,
   670→            predecessors,
   671→            stateUpdateSupplier
   672→        );
   673→
   674→        globalTopics.add(topic);
   675→        nodeFactories.put(sourceName, new SourceNodeFactory<>(
   676→            sourceName,
   677→            topics,
   678→            null,
   679→            timestampExtractor,
   680→            keyDeserializer,
   681→            valueDeserializer)
   682→        );
   683→        storeNameToReprocessOnRestore.put(storeFactory.storeName(),
   684→            reprocessOnRestore ?
   685→                Optional.of(new ReprocessFactory<>(stateUpdateSupplier, keyDeserializer, valueDeserializer))
   686→                : Optional.empty());
   687→        nodeToSourceTopics.put(sourceName, Arrays.asList(topics));
   688→        nodeGrouper.add(sourceName);
   689→        nodeFactory.addStateStore(storeFactory.storeName());
   690→        nodeFactories.put(processorName, nodeFactory);

